{
  "preguntes": [
    {
      "tipus": "comprensio",
      "pregunta": "Explica amb les teves paraules quina diferència hi ha entre la mida del peix més petit i la del tauro balena, i posa un exemple que ajudi a visualitzar aquesta diferència.",
      "resposta_esperada": "El peix més petit fa entre nou i deu mil·límetres, com la punta d'un dit petit, mentre que el tauro balena pot ser més llarg que cinc cotxes familiars i pesar més que tres elefants junts. Per exemple, si posem cinc cotxes en fila, el tauro balena seria més llarg que aquesta fila.",
      "justificacio_pedagogica": "Aquesta pregunta demana a l'alumne que sintetitzi la informació sobre les mides extremes dels peixos i que la relacioni amb exemples coneguts, demostrant comprensió de la magnitud de les diferències, no només record de dades."
    },
    {
      "tipus": "comprensio",
      "pregunta": "Quina relació hi ha entre la forma del peix lloro i la seva alimentació? Explica-ho detalladament.",
      "resposta_esperada": "El peix lloro té els llavis durs per arrencar el coral (que és dur com una roca) i dents planes per triturar-lo. Això li permet alimentar-se d'aquest tipus de menjar, que molts altres peixos no podrien menjar.",
      "justificacio_pedagogica": "La pregunta exigeix comprendre la connexió entre l'adaptació física (llavis i dents) i la funció (alimentació), demostrant comprensió de les relacions causa-efecte en el text."
    },
    {
      "tipus": "comprensio",
      "pregunta": "Per què les rajades aixequen nuvols de sorra quan neden? Quina avantatge els proporciona aquest comportament?",
      "resposta_esperada": "Les rajades aixequen nuvols de sorra per posar al descobert els crancs, que són un dels seus menjars favorits. Aquesta estratègia els permet trobar aliment sense haver de buscar-lo directament.",
      "justificacio_pedagogica": "Demana comprendre l'objectiu d'un comportament concret (aixecar sorra) i la seva utilitat, demostrant comprensió de la funció adaptativa en l'ecosistema."
    },
    {
      "tipus": "comprensio",
      "pregunta": "Com s'ho fa el peix erico per defensar-se dels seus enemics? Explica el procés i per què funciona.",
      "resposta_esperada": "El peix erico s'infla com un globus engolint aigua quan se sent amenaçat. Aquesta acció el fa més gran i difícil de menjar, espantant els seus enemics.",
      "justificacio_pedagogica": "Requereix comprendre el mecanisme de defensa i la seva lògica (fer-se més gran per dissuadir), demostrant comprensió de les estratègies de supervivència dels peixos."
    },
    {
      "tipus": "comprensio",
      "pregunta": "Quin tipus de peixos no tenen forma de peix tradicional? Nomena'n dos i explica com els ajuda la seva forma estranya.",
      "resposta_esperada": "El peix erico i el drac de foc no tenen forma de peix tradicional. El peix erico s'infla per defensar-se, i el drac de foc té aletes com ventalls i espines verinoses per avisar els depredadors. La seva forma els ajuda a camuflar-se o a espantar els enemics.",
      "justificacio_pedagogica": "Demana identificar exemples i comprendre la funció de les seves formes estranyes, demostrant comprensió de la diversitat i adaptació dels peixos."
    }
  ]
}

{
  "preguntes": [
    {
      "tipus": "comprensio",
      "pregunta": "Explica amb les teves paraules quins són els quatre principals arguments que el text presenta en contra de l'agricultura industrialitzada.",
      "resposta_esperada": "Els quatre arguments principals són: 1) La pèrdua de varietats agrícoles locals per l'ús de llavors modificades al laboratori; 2) La mecanització i l'ús massiu de productes químics que allunyen el productor del consumidor i generen dubtes sobre la qualitat dels aliments; 3) L'ús de cultius com la soja i el blat de moro per produir agrocombustibles en lloc d'aliments; 4) La dependència del petroli per a la producció, transport i processament dels cultius, que contribueix a l'emissió de CO2.",
      "justificacio_pedagogica": "Aquesta pregunta mesura la comprensió global del text, ja que requereix que l'alumne identifiqui i sintetitzi les idees principals presents en el text, demostrant que ha entès el contingut més enllà de recordar fets aïllats."
    },
    {
      "tipus": "comprensio",
      "pregunta": "Com afecta l'agricultura industrialitzada a la relació entre els productors i els consumidors segons el text?",
      "resposta_esperada": "L'agricultura industrialitzada allunya els productors dels consumidors, ja que els processos de producció estan molt mecanitzats i els productes recorren llargues distàncies per arribar als mercats. Això fa que els consumidors tinguin menys informació sobre com i on es produeixen els aliments que consumeixen.",
      "justificacio_pedagogica": "La pregunta avalua la comprensió de les conseqüències d'un dels arguments del text, demostrant que l'alumne ha entès la relació causa-efecte entre la industrialització i la desconnexió entre productor i consumidor."
    },
    {
      "tipus": "comprensio",
      "pregunta": "Per què el text afirma que l'ús de soja i blat de moro per produir agrocombustibles és un problema relacionat amb l'alimentació humana?",
      "resposta_esperada": "Perquè el 90% de la soja i el 40% del blat de moro produïts no s'utilitzen com a aliment per a persones, sinó per a combustible per a vehicles, reduint així la disponibilitat d'aquests cultius per a l'alimentació humana.",
      "justificacio_pedagogica": "Aquesta pregunta mesura la comprensió d'un dels arguments principals del text, requerint que l'alumne interpreti i relacioni dades concretes per explicar una conseqüència negativa de l'agricultura industrialitzada."
    },
    {
      "tipus": "comprensio",
      "pregunta": "Quina relació existeix entre l'agricultura industrialitzada i les emissions de CO2 segons el text?",
      "resposta_esperada": "L'agricultura industrialitzada contribueix a la meitat de les emissions actuals de CO2, principalment per la dependència del petroli en la producció, transport i processament dels cultius.",
      "justificacio_pedagogica": "La pregunta avalua la comprensió d'un dels efectes globals de l'agricultura industrialitzada, demostrant que l'alumne ha identificat i explicat la relació entre els processos descrits i les emissions de CO2."
    },
    {
      "tipus": "comprensio",
      "pregunta": "Quins dubtes planteja el text respecte a la qualitat i seguretat dels aliments produïts mitjançant agricultura industrialitzada?",
      "resposta_esperada": "El text planteja dubtes sobre l'ús de substàncies químiques (fertilitzants, pesticides) que garanteixen una bona conservació, sabor i aspecte als aliments, però que poden tenir efectes negatius en la salut i el medi ambient.",
      "justificacio_pedagogica": "Aquesta pregunta mesura la comprensió crítica del text, ja que requereix que l'alumne identifiqui i interpreti els possibles riscos associats als processos descrits, demostrant una comprensió profunda i no superficial."
    }
  ]
}

{
  "preguntes": [
    {
      "tipus": "comprensio",
      "pregunta": "Explica amb les teves paraules per què la pèrdua de biodiversitat en els cultius agrícoles fa que el nostre sistema alimentari sigui més vulnerable.",
      "resposta_esperada": "La pèrdua de biodiversitat implica que hi ha menys varietats de plantes i animals que es cultiven per alimentar-nos, cosa que redueix la capacitat de resistir canvis climàtics o problemes ambientals. Cada varietat té característiques úniques que poden ajudar a superar situacions adverses, i sense aquesta diversitat, el sistema alimentari es torna més fràgil.",
      "justificacio_pedagogica": "Aquesta pregunta demana a l'alumne que interpreti la idea principal del text (la relació entre biodiversitat i vulnerabilitat) i la reformuli amb les seves pròpies paraules, demostrant comprensió del concepte i no només record de dades."
    },
    {
      "tipus": "comprensio",
      "pregunta": "Quin és el problema principal que identifiquen els experts respecte a la distribució d'aliments, segons el text? Posa un exemple concret que il·lustri aquesta situació.",
      "resposta_esperada": "Els experts assenyalen que el problema no és la falta d'aliments disponibles, sinó la seva mala distribució. Per exemple, molts països que produeixen molts aliments els destinen a mercats globals en lloc de garantir-ne l'accés als seus habitants, cosa que els obliga a importar productes bàsics.",
      "justificacio_pedagogica": "La pregunta requereix que l'alumne identifiqui una idea secundària però rellevant (el problema de distribució) i la relacioni amb un exemple concret del text, demostrant comprensió i no només memòria."
    },
    {
      "tipus": "comprensio",
      "pregunta": "Quins dos factors principals esmenta el text com a reptes per a l'agricultura del futur? Justifica la teva resposta amb detalls del text.",
      "resposta_esperada": "Els dos factors principals són el canvi climàtic i el creixement de la població mundial. El text explica que el canvi climàtic afecta les condicions de cultiu, mentre que l'augment de població augmenta la demanda d'aliments, cosa que posa en risc la capacitat de produir prou menjar per a tothom.",
      "justificacio_pedagogica": "Aquesta pregunta exigeix que l'alumne sintetitzi informació de diferents parts del text i identifiqui les idees principals, demostrant comprensió global del contingut."
    },
    {
      "tipus": "comprensio",
      "pregunta": "Per què alguns experts creuen que les biotecnologies podrien ser una solució per a l'alimentació futura, segons el text?",
      "resposta_esperada": "Perquè les biotecnologies permeten desenvolupar cultius modificats genèticament que són més productius, més nutritius o més adaptats a condicions climàtiques extremes, cosa que podria ajudar a produir més aliments en menys temps i amb menys recursos.",
      "justificacio_pedagogica": "La pregunta demana a l'alumne que expliqui una solució proposada en el text i les seves característiques, demostrant comprensió de les idees i no només record de termes tècnics."
    },
    {
      "tipus": "comprensio",
      "pregunta": "El text presenta dues postures diferents sobre la possibilitat d'alimentar a tothom en el futur. Explica breument quines són i quins arguments utilitza cada una.",
      "resposta_esperada": "Una postura diu que el problema no és la quantitat d'aliments, sinó la seva mala distribució, ja que molts països tenen prou producció però no arriba als seus habitants. L'altra postura afirma que, en les condicions actuals, no es podrà produir prou menjar per a tothom sense augmentar la producció mitjançant biotecnologies.",
      "justificacio_pedagogica": "Aquesta pregunta requereix que l'alumne identifiqui i contrasti dues perspectives presents en el text, demostrant comprensió de les idees principals i la seva relació."
    }
  ]
}

{
  "preguntes": [
    {
      "tipus": "comprensio",
      "pregunta": "¿Quin impacte directe té l'augment de la temperatura mitjana diària en els recursos hídrics d'Espanya segons les dades de l'AEMET?",
      "resposta_esperada": "L'augment de la temperatura mitjana diària provoca una reducció dels recursos hídrics perquè augmenta les pèrdues d'aigua per evaporació i evapotranspiració.",
      "justificacio_pedagogica": "Aquesta pregunta demana a l'alumne que interpreti la relació causal entre dos fenòmens (augment de temperatura i pèrdua d'aigua) i que reformuli la informació del text sense copiar-la literalment, demostrant comprensió del concepte."
    },
    {
      "tipus": "comprensio",
      "pregunta": "¿Per què es preveu que els episodis de precipitacions que causen inundacions es reduiran un 5% cap al 2050?",
      "resposta_esperada": "Perquè els canvis en l'ús del sòl han disminuït el risc d'inundacions en les darreres dècades, fet que suavitza la possibilitat de crescudes fluvials importants.",
      "justificacio_pedagogica": "L'alumne ha d'explicar la connexió entre els canvis en l'ús del sòl i la reducció d'inundacions, demostrant que entén la causa-efecte i no només recorda dades aïllades."
    },
    {
      "tipus": "comprensio",
      "pregunta": "¿Quin contrast hi ha entre les aportacions mitjanes d'aigua als rius en el període 1995-1996 i 2005-2006 segons el Ministeri de Medi Ambient?",
      "resposta_esperada": "Les aportacions mitjanes d'aigua als rius van disminuir de 108.809 hectòmetres cúbics a 93.232 hectòmetres cúbics, una reducció que reflecteix la pèrdua de recursos hídrics.",
      "justificacio_pedagogica": "La pregunta exigeix que l'alumne sintetitzi i compare dades numèriques del text, demostrant comprensió de la tendència i no només la memorització de xifres."
    },
    {
      "tipus": "comprensio",
      "pregunta": "¿Com s'explica que Espanya s'enfronti a un col·lapse hidric malgrat la disminució de la demanda d'aigua?",
      "resposta_esperada": "La disminució de la demanda d'aigua no compensa la pèrdua de recursos hídrics causada per la reducció de pluges, l'augment de temperatures i els canvis en l'ús del sòl.",
      "justificacio_pedagogica": "L'alumne ha d'integrar múltiples factors del text (pluja, temperatura, demanda, ús del sòl) per explicar una situació complexa, demostrant comprensió global."
    },
    {
      "tipus": "comprensio",
      "pregunta": "¿Quin paper juguen els informes d'organitzacions ecologistes en l'avaluació del risc hidric a Espanya?",
      "resposta_esperada": "Els informes d'organitzacions ecologistes proporcionen dades i projeccions sobre la reducció de recursos hídrics, els canvis en els episodis de precipitacions i els efectes del canvi climàtic, ajudant a comprendre l'abast del problema.",
      "justificacio_pedagogica": "La pregunta requereix que l'alumne identifiqui i expliqui la funció dels informes en el context del text, demostrant comprensió del seu valor informatiu i no només la seva existència."
    }
  ]
}

